                  <td key={ci} style={{ padding: "12px 16px", fontSize: "13px", color: ci === 0 ? "var(--text-2)" : "var(--text-1)", fontWeight: ci === 0 ? 600 : 400, lineHeight: 1.55, verticalAlign: "top" }}>{cell}</td>
